/**
 * Email notification handler — formats and dispatches email notifications
 * for order lifecycle events via EventBus subscriptions.
 *
 * Follows the same EventBus-driven pattern as NotificationService.
 * See decision record in .twining/ for rationale on using EventBus.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<string, string> = {
  pending: 'Pending',
  confirmed: 'Confirmed',
  shipped: 'Shipped',
  delivered: 'Delivered',
  cancelled: 'Cancelled',
};

function statusLabel(status: string): string {
  return STATUS_LABELS[status] ?? status;
}

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register EventBus handlers for order events that require email notifications.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Send email confirmation when a new order is created.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
      )
      .join('\n');

    const itemText = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Thank you for your order, ${event.user.name}!</p>
<p>Order ID: <strong>${event.order.id}</strong></p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Thank you for your order, ${event.user.name}!

Order ID: ${event.order.id}

Items:
${itemText}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send email notification when an order's status changes.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status change email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const newLabel = statusLabel(event.newStatus);
    const prevLabel = statusLabel(event.previousStatus);

    const htmlBody = `<h1>Order Status Update</h1>
<p>Your order <strong>${event.order.id}</strong> has been updated.</p>
<p>Status: <strong>${prevLabel}</strong> &rarr; <strong>${newLabel}</strong></p>
${this.getStatusMessage(event.newStatus)}`;

    const textBody = `Order Status Update

Your order ${event.order.id} has been updated.

Status: ${prevLabel} -> ${newLabel}

${this.getStatusTextMessage(event.newStatus)}`;

    this.sendEmail({
      to: event.order.userId,
      subject: `Order ${event.order.id} - ${newLabel}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Get an HTML status-specific message for the email body.
   */
  private getStatusMessage(status: string): string {
    switch (status) {
      case 'confirmed':
        return '<p>We have confirmed your order and it is being prepared.</p>';
      case 'shipped':
        return '<p>Your order has been shipped and is on its way!</p>';
      case 'delivered':
        return '<p>Your order has been delivered. Enjoy!</p>';
      case 'cancelled':
        return '<p>Your order has been cancelled. If you have questions, please contact support.</p>';
      default:
        return '';
    }
  }

  /**
   * Get a plain-text status-specific message for the email body.
   */
  private getStatusTextMessage(status: string): string {
    switch (status) {
      case 'confirmed':
        return 'We have confirmed your order and it is being prepared.';
      case 'shipped':
        return 'Your order has been shipped and is on its way!';
      case 'delivered':
        return 'Your order has been delivered. Enjoy!';
      case 'cancelled':
        return 'Your order has been cancelled. If you have questions, please contact support.';
      default:
        return '';
    }
  }

  /**
   * Send an email (in-memory for this demo).
   */
  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      ...params,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get sent emails for a specific recipient.
   */
  getEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let handler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    handler = new EmailNotificationHandler(eventBus);
  });

  describe('order:created email', () => {
    it('should send confirmation email on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.htmlBody).toContain('Widget');
      expect(emails[0]?.htmlBody).toContain('$20.00');
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('$20.00');
    });

    it('should include all items in confirmation email', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Widget');
      expect(emails[0]?.htmlBody).toContain('Gadget');
      expect(emails[0]?.textBody).toContain('Widget x2');
      expect(emails[0]?.textBody).toContain('Gadget x1');
    });

    it('should address user by name in email', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emails = handler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Bob');
      expect(emails[0]?.textBody).toContain('Bob');
    });
  });

  describe('order:status-changed email', () => {
    const makeStatusEvent = (
      previousStatus: string,
      newStatus: string,
    ): OrderStatusChangedEvent => ({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as OrderStatusChangedEvent['order']['status'],
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date(),
    });

    it('should send email on status change to confirmed', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.subject).toContain('Confirmed');
      expect(emails[0]?.htmlBody).toContain('Pending');
      expect(emails[0]?.htmlBody).toContain('Confirmed');
      expect(emails[0]?.htmlBody).toContain('being prepared');
      expect(emails[0]?.textBody).toContain('being prepared');
    });

    it('should send email on status change to shipped', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Shipped');
      expect(emails[0]?.htmlBody).toContain('on its way');
      expect(emails[0]?.textBody).toContain('on its way');
    });

    it('should send email on status change to delivered', async () => {
      await eventBus.emit(makeStatusEvent('shipped', 'delivered'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Delivered');
      expect(emails[0]?.htmlBody).toContain('Enjoy');
      expect(emails[0]?.textBody).toContain('Enjoy');
    });

    it('should send email on status change to cancelled', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'cancelled'));

      const emails = handler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.subject).toContain('Cancelled');
      expect(emails[0]?.htmlBody).toContain('contact support');
      expect(emails[0]?.textBody).toContain('contact support');
    });

    it('should include both previous and new status in email', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const emails = handler.getSentEmails();
      expect(emails[0]?.htmlBody).toContain('Confirmed');
      expect(emails[0]?.htmlBody).toContain('Shipped');
      expect(emails[0]?.textBody).toContain('Confirmed');
      expect(emails[0]?.textBody).toContain('Shipped');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(handler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(handler.getEmailsForRecipient('alice@example.com')).toHaveLength(1);
      expect(handler.getEmailsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      handler.clearEmails();
      expect(handler.getSentEmailCount()).toBe(0);
    });

    it('should accumulate emails across multiple events', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      expect(handler.getSentEmailCount()).toBe(2);
      expect(handler.getSentEmails()[0]?.subject).toContain('Confirmed');
      expect(handler.getSentEmails()[1]?.subject).toContain('Shipped');
    });
  });

  describe('coexistence with NotificationService', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();

      // Both handlers subscribe to the same EventBus
      const sharedBus = new EventBus();
      const notifService = new NotificationService(sharedBus);
      const emailHandler = new EmailNotificationHandler(sharedBus);

      await sharedBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      // Both should have received the event
      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);
    });
  });
});

